import{_ as a,o as b,c as t,j as r,a as p,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"忍义手","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/改造/6.一次性改造/忍义手.md","filePath":"4.资源分区/2.改造与功法/改造/6.一次性改造/忍义手.md"}'),s={name:"4.资源分区/2.改造与功法/改造/6.一次性改造/忍义手.md"};function o(d,e,l,_,i,c){return b(),t("div",null,[...e[0]||(e[0]=[r("h1",{id:"忍义手",tabindex:"-1"},[p("忍义手 "),r("a",{class:"header-anchor",href:"#忍义手","aria-label":'Permalink to "忍义手"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新秩序009")])])],-1),n('<h1 id="忍义手-1" tabindex="-1">忍义手 <a class="header-anchor" href="#忍义手-1" aria-label="Permalink to &quot;忍义手&quot;">​</a></h1><p>忍义手</p><p>出自只狼世界的特殊机关义肢，由雕佛师亲手所制，其结构分为三段：固定连接肉体的肘部、产生力量以及具有传动结构的臂部、如同真人手指搬精巧灵活的手部。</p><p>D+1100<br> 前提：力量3、具有左臂<br> ——“对于一匹独臂的孤狼，这是不错的獠牙。”<br> 改造者的左手臂被永久性的替换为忍义手，这意味着：<br> 1、改造者的左手力量属性被恒定为11，这部分力量属性可以不受属性上限的制约，但即使改造者以后的力量达到更高也不会改变忍义手的力量数值。<br> 2、左臂上的肢体残障点数不会对改造者造成减值，但如果左臂上的肢体残障点数进入严重状态，忍义手同样会瘫痪；如果进入毁灭状态，则忍义手在该毁灭状态被移除前，都无法再度使用。</p><p>绳勾：臂部的机关传动轴在手部向内收缩时会弹射出绳勾，可以帮助改造者攀登或者飞跃至较高位置。<br> 以移动动作使用忍义手向一个目标位置弹出绳勾，绳勾最长的弹射距离为45米，只要目标位置具有可抓取固定的物体，绳勾就会牢牢的将改造者与该物体连接，之后改造者可以一个花招/反射动作启动忍义手上的缆机将自身拉到目标位置。<br> 需要注意的是，射出的绳勾并不是绝对无法破坏，敌方可对改造者进行一个减值为8的部位攻击，只要造成的伤害达到5点，绳勾就会被破坏，被破坏的绳勾在此场景内将无法使用。</p><p>忍义手的臂部可装备特殊的机关装置，但这些机关装置的使用均需要消耗【纸人】作为代价使用。<br> 【纸人】：似乎是被死者灵魂所结附的特殊纸制小人，其上附有相当程度的念力。<br> 价格：25分/个。<br> 使用上限：20<br> 携带上限：200<br> 使用上限指一场景内的使用上限。<br> 纸人可能在剧本内因剧情原因获得。</p><p>机关装置<br> 机关装置均为物品，故而不提供属性。<br> 机关装置同时只能装备一个，切换机关装置需要在战斗中花费一个迅捷动作进行。<br> 特殊的，在购买D级机关装置的同时，额外花费D+500可选择另外两个同价格的机关装置。这些机关装置均视为科技本质。</p><p>吹火筒<br> D+500<br> 消耗纸人：3<br> 经过改造后在手臂上加装了含有硝石的黑色筒状装置，可以吹出火焰。<br> 以标准动作使用，对前方十五米内锥形范围的所有人造成10L火焰伤害，反射豁免。</p><p>手里剑<br> D+500<br> 消耗纸人：1<br> 从寄鹰众手中获得的手里剑车进行改造后获得的装置，可以投掷出手里剑。<br> 以标准动作使用，对20米内的敌人投掷手里剑，使用Dp为24+3、高速4的远程攻击对敌人进行攻击。</p><p>机关斧<br> D+500<br> 消耗纸人：2<br> 飞天猿猴赖以成名的武器，经过改造被装至忍义手中，展开后对笨重的敌人足以造成惊人的杀伤，但武器本身的缺陷使得其对敏捷程度较高的敌人效果不佳。<br>   迅捷动作将忍义手上的机关斧展开组装，本轮内可使用标准动作机关斧对敌人进行攻击。<br> 武器伤害：7L<br> 体积：3<br> 专业：斧<br> 特性：威猛12<br> 如果攻击时目标的闪避/基础防御高于使用者的敏捷属性，则本武器的威猛特性只生效一半。<br> 如果攻击时敌方处于格挡状态，且其在计算防御属性后不保留任何格挡防御，则目标在他自身的下次行动轮结束前不能进行格挡。这是C级别创伤来源的胁迫效果。</p><p>锈丸<br> D+500<br> 消耗纸人：1<br> 这是一节几乎已经被锈蚀所覆盖的短刃，脆弱不堪的刀身仿佛随时可能断裂，纵使如此，其刀刃依旧锋利无匹。<br> 以迅捷动作将绣丸弹出手腕并固定，此时忍义手视为持握着一柄武器。锈丸可用自由动作收回，如果不收回锈丸，则后续每一轮使用者都需要花费1个纸人。<br> 武器伤害：10L<br> 体积：2<br> 专业：刀/剑<br> 特性：<br> 【易损】：计算防御后，目标每保有1点盔甲/天生防御，锈丸的武器伤害就下降2L。<br> 【锈毒】：在计算防御后，如果锈丸的武器伤害高于对方的盔甲与天生防御，且此次攻击对目标造成至少1点严重伤害，目标就需要进行强韧豁免，DC为伤害值。如果豁免失败，目标就需要承受5点毒素异常点数。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',13)])])}const D=a(s,[["render",o]]);export{f as __pageData,D as default};
